type Filter = "all" | "facts" | "preferences" | "decisions" | "people";

type Prov = "told" | "derived" | "confirmed";

/* A single memory card. Owns its own forgotten/undo state — the forget gesture
 * is control made literal (struck-through, curate hidden, undo offered). */
function Mem({
  recent,
  text,
  tag,
  prov,
  provLabel,
  fresh,
}: {
  recent?: boolean;
  text: ReactNode;
  tag?: string;
  prov: Prov;
  provLabel: string;
  fresh: string;
}) {
  const [forgotten, setForgotten] = useState(false);

  return (
    <div className={`mem${recent ? " recent" : ""}${forgotten ? " forgotten" : ""}`}>
      <div className="mem-text">{text}</div>
      <div className="mem-foot">
        {tag && <span className="tag">{tag}</span>}
        <span className={`prov ${prov}`}>
          <span className="mk" />
          {provLabel}
        </span>
        <span className="fresh">· {fresh}</span>
        <span className="mem-curate">
          <button className="cbtn" type="button">Correct</button>
          <button className="cbtn forget" type="button" onClick={() => setForgotten(true)}>
            Forget
          </button>
        </span>
        <span className="fstamp">Forgotten</span>
        <button className="undo" type="button" onClick={() => setForgotten(false)}>
          ↺ Undo
        </button>
      </div>
    </div>
  );
}

